class Solution {
    public int findNumberOfLIS(int[] nums) {
        int n = nums.length;
        int memo[][] = new int[n + 1][n + 1];

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (i == j) {
                    memo[i][j] = 1;
                } else if (nums[i - 1] < nums[j]) {
                    memo[i][j] = memo[i - 1][j];
                } else {
                    memo[i][j] = 1 + max(memo[i][j - 1], memo[i - 1][j]);
                }
            }
        }

        return memo[n][n];
    }
}
